nil = None


def cons(first, rest):
    return (first, rest)


def car(pair):
    return pair[0]


def cdr(pair):
    return pair[1]


def length(items):
    if items is nil:
        return 0
    return 1 + length(cdr(items))


def getitem(items, n):
    if n == 0:
        return car(items)
    return getitem(cdr(items), n - 1)


one_through_four = cons(1, cons(2, cons(3, cons(4, nil))))
print(length(one_through_four))
print(getitem(one_through_four, 2))
